async (params, browser) => {
  // Open Threads post
  await browser.open(`${params.post_url}`)

  // Wait for post to load
  await browser.waitForSelector('[class*=\'ThreadItem\'], article, div[role=\'article\'], [data-pressable-container=\'true\']', 15000)

  // Let post fully render
  await browser.wait(2500)

  // Like the post
  const result = await browser.evaluate(`const mainPost = document.querySelector('[class*="ThreadItem"], article, div[role="article"], [data-pressable-container="true"]'); if (!mainPost) return { success: false, message: 'Post not found' }; const unlikeSvg = mainPost.querySelector('svg[aria-label*="Unlike"], svg[aria-label*="unlike"], [class*="liked"] svg, [aria-label*="Liked"]'); if (unlikeSvg) { return { success: true, message: 'Post is already liked', already_liked: true, post_url: params.post_url }; } const likeSvg = mainPost.querySelector('svg[aria-label*="Like"], svg[aria-label*="like"]'); if (likeSvg) { const likeBtn = likeSvg.closest('button') || likeSvg.closest('div[role="button"]') || likeSvg.parentElement; if (likeBtn) { likeBtn.click(); await new Promise(r => setTimeout(r, 1500)); const confirmUnlike = mainPost.querySelector('svg[aria-label*="Unlike"], svg[aria-label*="unlike"], [class*="liked"] svg, [aria-label*="Liked"]'); return { success: !!confirmUnlike, message: confirmUnlike ? 'Post liked successfully' : 'Like button clicked but could not confirm', post_url: params.post_url }; } } const heartBtns = mainPost.querySelectorAll('[role="button"], button'); for (const btn of heartBtns) { const svg = btn.querySelector('svg'); const ariaLabel = btn.getAttribute('aria-label') || (svg ? svg.getAttribute('aria-label') : '') || ''; if (ariaLabel.toLowerCase().includes('like') && !ariaLabel.toLowerCase().includes('unlike')) { btn.click(); await new Promise(r => setTimeout(r, 1500)); return { success: true, message: 'Like button clicked', post_url: params.post_url }; } } return { success: false, message: 'Like button not found. Make sure you are logged in and the post URL is valid.' }`)

  // Wait for like to register
  await browser.wait(1000)

  return result
}
